package kyo.ffi.codegen.emitters

import EmitterFixtures.*
import kyo.ffi.codegen.model.*

class JvmEmitterTest extends kyo.test.Test[Any]:

    // -------------------------------------------------------------------------
    // Section 1: header + companion basics
    // -------------------------------------------------------------------------

    "emits an AUTO-GENERATED banner and package clause" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(
                mkMethod("noop", "noop", Nil, ReturnShape.Void)
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.startsWith("// AUTO-GENERATED by kyo-ffi-codegen"))
        assert(src.contains("package kyo.example"))
        assert(src.contains("import java.lang.foreign.*"))
        assert(src.contains("import kyo.ffi.*"))
        assert(src.contains(
            "import kyo.ffi.internal.{AbiCheck, NativeLoader, Scratch, Layouts, StructAbiCheck, UpcallBridge}"
        ))
    }

    "companion loads the named library, calls AbiCheck.verify, and defines the capture Linker.Option" in {
        val spec = mkTrait(
            "Simple",
            "kyo_simple",
            List(
                // Non-blocking + Array → critOn emitted at companion scope.
                mkMethod("f", "f", List(ParamSpec("x", TypeRef.ArrayT(TypeRef.IntT))), ReturnShape.Primitive(TypeRef.IntT))
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("""AbiCheck.verify(1, "kyo.example.Simple")"""))
        assert(src.contains(""" NativeLoader.load("kyo_simple")"""))
        assert(src.contains("""Linker.Option.captureCallState("errno")"""))
        // critOff is JDK 22+ and is no longer emitted in the no-array path; critOn appears only when needed.
        assert(src.contains("Linker.Option.critical(true)"))
    }

    // -------------------------------------------------------------------------
    // Section 2: Linker.Option matrix (§4.6)
    // -------------------------------------------------------------------------

    "non-blocking + no array → capture only (critOff is JDK 22+, default downcall is equivalent on JDK 21)" in {
        val m = mkMethod("f", "f", List(ParamSpec("x", TypeRef.IntT)), ReturnShape.Primitive(TypeRef.IntT))
        assert(JvmEmitter.emitLinkerOptions(m) == "capture")
    }

    "non-blocking + array param → capture, critOn" in {
        val m = mkMethod(
            "f",
            "f",
            List(ParamSpec("a", TypeRef.ArrayT(TypeRef.ByteT)), ParamSpec("n", TypeRef.IntT)),
            ReturnShape.Primitive(TypeRef.IntT)
        )
        assert(JvmEmitter.emitLinkerOptions(m) == "capture, critOn")
    }

    "blocking + no array → capture only" in {
        val m = mkMethod(
            "f",
            "f",
            List(ParamSpec("x", TypeRef.IntT)),
            ReturnShape.Primitive(TypeRef.IntT),
            blocking = true
        )
        assert(JvmEmitter.emitLinkerOptions(m) == "capture")
    }

    "blocking + array → capture only" in {
        val m = mkMethod(
            "f",
            "f",
            List(ParamSpec("a", TypeRef.ArrayT(TypeRef.ByteT)), ParamSpec("n", TypeRef.IntT)),
            ReturnShape.Primitive(TypeRef.IntT),
            blocking = true
        )
        assert(JvmEmitter.emitLinkerOptions(m) == "capture")
    }

    // -------------------------------------------------------------------------
    // Section 3: FunctionDescriptor emission
    // -------------------------------------------------------------------------

    "void-return uses FunctionDescriptor.ofVoid" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(
                mkMethod("close", "tcp_close", List(ParamSpec("fd", TypeRef.IntT)), ReturnShape.Void)
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("FunctionDescriptor.ofVoid(JAVA_INT)"))
    }

    "multi-value return's FunctionDescriptor has ADDRESS trailing out-params" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "Tcp",
            "kyo_tcp",
            List(mkMethod(
                "tcpConnect",
                "tcp_connect",
                List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                ReturnShape.MultiValue(cr),
                blocking = true
            )),
            structs = List(cr)
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("FunctionDescriptor.of(JAVA_INT, ADDRESS, JAVA_INT, ADDRESS)"))
    }

    // -------------------------------------------------------------------------
    // Section 4: method body / marshalling
    // -------------------------------------------------------------------------

    "String param body calls __kyoScratch$.allocUtf8 and passes the segment" in {
        val spec = mkTrait(
            "Log",
            "kyo_log",
            List(
                mkMethod(
                    "log",
                    "log_line",
                    List(ParamSpec("msg", TypeRef.StringT)),
                    ReturnShape.Void
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        // The allocUtf8 call threads binding FQN + method name so the diagnostic in `FfiErrors.scratchSpilled`
        // names the origin when the oversized-spill log is enabled.
        assert(src.contains("""val msgSeg = __kyoScratch$.allocUtf8(msg, "kyo.example.Log", "log")"""))
        assert(src.contains("logMH.invokeExact(errnoSeg, msgSeg)"))
    }

    "Buffer param body casts .raw to MemorySegment" in {
        val spec = mkTrait(
            "Tcp",
            "kyo_tcp",
            List(
                mkMethod(
                    "tcpRead",
                    "tcp_read",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("maxLen", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        // `Buffer.Raw` unwrap routes through `FfiUnsafe.expect` with binding + method context so alien
        // `Buffer.Raw` implementations produce a diagnostic instead of a silent `ClassCastException`.
        assert(src.contains(
            """val bufSeg = kyo.ffi.internal.FfiUnsafe.expect[MemorySegment](buf.raw.asInstanceOf[AnyRef], classOf[MemorySegment], "MemorySegment on JVM", "kyo.example.Tcp", "tcpRead")"""
        ))
        assert(src.contains("tcpReadMH.invokeExact(errnoSeg, fd, bufSeg, maxLen)"))
    }

    "Array + blocking → copy loop into scratch" in {
        val spec = mkTrait(
            "Hash",
            "kyo_hash",
            List(
                mkMethod(
                    "digestBlocking",
                    "digest_blocking",
                    List(
                        ParamSpec("data", TypeRef.ArrayT(TypeRef.ByteT)),
                        ParamSpec("len", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("val dataBps = 1L"))
        // alloc takes binding FQN + method name for spill diagnostics.
        assert(src.contains(
            """val dataSeg = __kyoScratch$.alloc(data.length.toLong * dataBps, dataBps, "kyo.example.Hash", "digestBlocking")"""
        ))
        assert(src.contains("val dataRaw = dataSeg.asInstanceOf[Buffer.Raw]"))
        assert(src.contains("while dataI < data.length do"))
        assert(src.contains("Layouts.byteL.write(dataRaw"))
    }

    "Array + non-blocking → MemorySegment.ofArray" in {
        val spec = mkTrait(
            "Hash",
            "kyo_hash",
            List(
                mkMethod(
                    "digestFast",
                    "digest_fast",
                    List(
                        ParamSpec("data", TypeRef.ArrayT(TypeRef.ByteT)),
                        ParamSpec("len", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT)
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("val dataSeg = MemorySegment.ofArray(data)"))
        assert(src.contains("capture, critOn"))
    }

    "multi-value return allocates a single coalesced out-segment block and slices per field" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "Tcp",
            "kyo_tcp",
            List(mkMethod(
                "tcpConnect",
                "tcp_connect",
                List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                ReturnShape.MultiValue(cr),
                blocking = true
            )),
            structs = List(cr)
        )
        val src = JvmEmitter.emit(spec)
        // Out-params are coalesced into a single scratch allocation. There is NO per-field
        // `val pendingOut = __kyoScratch$.alloc(...)`, the former per-field allocator is replaced by a
        // single `__kyoMultiOut$` block and per-field `asSlice` views anchored at a fixed offset.
        assert(!src.contains("""val pendingOut = __kyoScratch$.alloc"""))
        assert(src.contains("""val __kyoMultiOut$ = __kyoScratch$.alloc(4L, 4L, "kyo.example.Tcp", "tcpConnect")"""))
        assert(src.contains("""val pendingOut = __kyoMultiOut$.asSlice(0L, 4L)"""))
        assert(src.contains("kyo.example.ConnectResult(retVal, pendingOut.get(JAVA_INT, 0L))"))
    }

    "multi-value return with 5 trailing out-params uses exactly one __kyoScratch$.alloc for the out-param block" in {
        // 5 trailing fields = 6 total fields in the MultiValue case class; head is primitive-returned, remaining
        // 5 are out-pointer writes. The emitter coalesces them into a single block with per-field offset slices.
        val fiveOut = StructSpec(
            "kyo.example.FiveOut",
            "FiveOut",
            List(
                StructField("head", TypeRef.IntT),
                StructField("a", TypeRef.IntT),
                StructField("b", TypeRef.LongT),
                StructField("c", TypeRef.DoubleT),
                StructField("d", TypeRef.IntT),
                StructField("e", TypeRef.LongT)
            ),
            packed = false
        )
        val spec = mkTrait(
            "Five",
            "kyo_five",
            List(mkMethod(
                "call",
                "five_call",
                Nil,
                ReturnShape.MultiValue(fiveOut)
            )),
            structs = List(fiveOut)
        )
        val src = JvmEmitter.emit(spec)
        val allocSites =
            raw"__kyoScratch\$$\.alloc\b".r.findAllMatchIn(src).size
        // 1 for errnoSeg + 1 coalesced multi-out block = 2 total. The former 5-per-field count would be 6.
        assert(allocSites == 2)
        // Single coalesced block is allocated to hold 5 fields (4 + 8 + 8 + 4 + 8 = 32 bytes natural-aligned).
        assert(src.contains("""val __kyoMultiOut$ = __kyoScratch$.alloc("""))
        // Per-field slices anchored on the coalesced block at their natural-alignment offsets.
        assert(src.contains("""val aOut = __kyoMultiOut$.asSlice(0L, 4L)"""))
        // `b: Long` is 8-aligned → offset 8 (after 4-byte `a` + 4 bytes of padding).
        assert(src.contains("""val bOut = __kyoMultiOut$.asSlice(8L, 8L)"""))
        // `c: Double` is 8-aligned → offset 16.
        assert(src.contains("""val cOut = __kyoMultiOut$.asSlice(16L, 8L)"""))
        // `d: Int` → offset 24.
        assert(src.contains("""val dOut = __kyoMultiOut$.asSlice(24L, 4L)"""))
        // `e: Long` → offset 32 (after 4-byte `d` + 4 bytes of padding).
        assert(src.contains("""val eOut = __kyoMultiOut$.asSlice(32L, 8L)"""))
    }

    "packed struct-by-value uses byte-aligned offsets (no padding between fields)" in {
        val ps = StructSpec(
            "kyo.example.Packed",
            "Packed",
            List(StructField("flag", TypeRef.ByteT), StructField("value", TypeRef.IntT)),
            packed = true
        )
        val spec = mkTrait(
            "PackedTrait",
            "kyo_packed",
            List(mkMethod(
                "send",
                "send_packed",
                List(ParamSpec("p", TypeRef.StructT(ps.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(ps)
        )
        val src = JvmEmitter.emit(spec)
        // Layout uses .withByteAlignment(1L) per field.
        assert(src.contains("JAVA_BYTE.withByteAlignment(1L)"))
        assert(src.contains("JAVA_INT.withByteAlignment(1L)"))
        // Byte field is at offset 0, Int field follows immediately at offset 1 (no padding).
        assert(src.contains("pSeg.set(JAVA_BYTE, 0L, p.flag)"))
        assert(src.contains("pSeg.set(JAVA_INT, 1L, p.value)"))
        // Sanity: should NOT pad to offset 4.
        assert(!src.contains("pSeg.set(JAVA_INT, 4L, p.value)"))
    }

    "non-packed struct-by-value uses natural alignment (padding inserted)" in {
        val us = StructSpec(
            "kyo.example.Unpacked",
            "Unpacked",
            List(StructField("flag", TypeRef.ByteT), StructField("value", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "UnpackedTrait",
            "kyo_unpacked",
            List(mkMethod(
                "send",
                "send_unpacked",
                List(ParamSpec("u", TypeRef.StructT(us.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(us)
        )
        val src = JvmEmitter.emit(spec)
        // Byte at 0, Int padded to offset 4.
        assert(src.contains("uSeg.set(JAVA_BYTE, 0L, u.flag)"))
        assert(src.contains("uSeg.set(JAVA_INT, 4L, u.value)"))
    }

    "nested-struct param with a String field emits a legal local identifier (not a dotted member selection)" in {
        // Regression for #1683: a struct param containing a nested struct that contains a String field made the
        // emitter build the scratch-temp name from the dotted access path (`contact.address`), producing
        // `val contact.address_city_cs = ...` which the parser reads as a member selection on `contact`.
        val address = StructSpec(
            "kyo.example.Address",
            "Address",
            List(StructField("zip", TypeRef.IntT), StructField("city", TypeRef.StringT)),
            packed = false
        )
        val contact = StructSpec(
            "kyo.example.Contact",
            "Contact",
            List(
                StructField("id", TypeRef.IntT),
                StructField("name", TypeRef.StringT),
                StructField("address", TypeRef.StructT(address.fqcn))
            ),
            packed = false
        )
        val spec = mkTrait(
            "ContactBindings",
            "contacts",
            List(mkMethod(
                "contactsRouteCode",
                "contacts_route_code",
                List(ParamSpec("contact", TypeRef.StructT(contact.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(address, contact)
        )
        val src = JvmEmitter.emit(spec)
        // The temp for the nested String field uses underscores throughout, and the allocUtf8 still reads from the
        // real dotted access expression `contact.address.city`.
        assert(src.contains(
            """val contact_address_city_cs = __kyoScratch$.allocUtf8(contact.address.city, "kyo.example.ContactBindings", "contactsRouteCode")"""
        ))
        // The top-level String field keeps its existing flat name.
        assert(src.contains(
            """val contact_name_cs = __kyoScratch$.allocUtf8(contact.name, "kyo.example.ContactBindings", "contactsRouteCode")"""
        ))
        // The broken dotted local name must not appear.
        assert(!src.contains("val contact.address_city_cs"))
        // And the whole thing parses.
        val (ok, errs) = ScalaParseProbe.parses(src)
        assert(ok == true, s"emitted source did not parse:\n$src\n\nerrors:\n$errs\n")
    }

    "struct-by-value param allocates scratch and writes each field" in {
        val ts = StructSpec(
            "kyo.example.Timespec",
            "Timespec",
            List(StructField("sec", TypeRef.LongT), StructField("nsec", TypeRef.LongT)),
            packed = false
        )
        val spec = mkTrait(
            "Time",
            "kyo_time",
            List(mkMethod(
                "sleep",
                "sleep_ts",
                List(ParamSpec("ts", TypeRef.StructT(ts.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(ts)
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains(
            """val tsSeg = __kyoScratch$.alloc(timespecLayout.byteSize(), timespecLayout.byteAlignment(), "kyo.example.Time", "sleep")"""
        ))
        assert(src.contains("tsSeg.set(JAVA_LONG, 0L, ts.sec)"))
        assert(src.contains("tsSeg.set(JAVA_LONG, 8L, ts.nsec)"))
    }

    "small (16-byte) simple-primitive struct uses the default field-by-field write path, NOT writeBulk" in {
        val small = StructSpec(
            "kyo.example.Small",
            "Small",
            // 16 bytes: Long + Long, under the default 128 B threshold.
            List(StructField("a", TypeRef.LongT), StructField("b", TypeRef.LongT)),
            packed = false
        )
        val spec = mkTrait(
            "SmallStructTrait",
            "kyo_small",
            List(mkMethod(
                "take",
                "take_small",
                List(ParamSpec("s", TypeRef.StructT(small.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(small)
        )
        val src = JvmEmitter.emit(spec)
        // The bulk-write marker + helper invocation must NOT appear for small structs.
        assert(!src.contains("writeBulk"))
        // The standard field-by-field writes remain.
        assert(src.contains("sSeg.set(JAVA_LONG, 0L, s.a)"))
        assert(src.contains("sSeg.set(JAVA_LONG, 8L, s.b)"))
    }

    "large (256-byte) simple-primitive struct emits the writeBulk marker path" in {
        // 256 bytes = 32 Long fields (8 bytes each). All primitives, no nested / String / Buffer fields,
        // so the struct qualifies for the bulk-write path. The default threshold is 128 bytes.
        val fields = (1 to 32).map(i => StructField(s"f$i", TypeRef.LongT)).toList
        val big = StructSpec(
            "kyo.example.Big",
            "Big",
            fields,
            packed = false
        )
        val spec = mkTrait(
            "BigStructTrait",
            "kyo_big",
            List(mkMethod(
                "take",
                "take_big",
                List(ParamSpec("b", TypeRef.StructT(big.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(big)
        )
        val src = JvmEmitter.emit(spec)
        // The emitter annotates the bulk-write path with a marker comment naming the struct's FQN and byte
        // size so codegen tests and human readers can spot the path selection. The marker is stable across
        // regen so snapshots don't churn.
        assert(src.contains("// __kyoStructBulkWrite$: kyo.example.Big (256 bytes)"))
        // Field writes still happen, the bulk path is a marker + predictable field sequence, not a
        // behavioural change. All 32 fields must still be written to the scratch segment.
        assert(src.contains("bSeg.set(JAVA_LONG, 0L, b.f1)"))
        assert(src.contains("bSeg.set(JAVA_LONG, 248L, b.f32)"))
    }

    "struct with a String field is NOT eligible for writeBulk even when above the threshold" in {
        // Even at ≥128 bytes, a struct containing non-primitive fields (here a trailing String / C char*)
        // falls back to the field-by-field path, the bulk pattern only applies to strictly primitive
        // layouts because pointer fields require per-field allocUtf8 setup.
        val mixedFields = (1 to 16).map(i => StructField(s"f$i", TypeRef.LongT)).toList :+
            StructField("name", TypeRef.StringT) // 128 + 8 = 136 bytes
        val mixed = StructSpec(
            "kyo.example.Mixed",
            "Mixed",
            mixedFields,
            packed = false
        )
        val spec = mkTrait(
            "MixedStructTrait",
            "kyo_mixed",
            List(mkMethod(
                "take",
                "take_mixed",
                List(ParamSpec("m", TypeRef.StructT(mixed.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(mixed)
        )
        val src = JvmEmitter.emit(spec)
        assert(!src.contains("writeBulk"))
    }

    "Unit-return method emits invokeExact without asInstanceOf" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(
                mkMethod("close", "tcp_close", List(ParamSpec("fd", TypeRef.IntT)), ReturnShape.Void)
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("closeMH.invokeExact(errnoSeg, fd)"))
        assert(!src.contains(".asInstanceOf[Unit]"))
    }

    "method-handle block references lib.find and the computed descriptor" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(
                mkMethod(
                    "add",
                    "add_ints",
                    List(ParamSpec("a", TypeRef.IntT), ParamSpec("b", TypeRef.IntT)),
                    ReturnShape.Primitive(TypeRef.IntT)
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("""lib.find("add_ints").orElseThrow()"""))
        assert(src.contains("FunctionDescriptor.of(JAVA_INT, JAVA_INT, JAVA_INT)"))
        assert(src.contains("private val addMH: MethodHandle = linker.downcallHandle("))
    }

    // -------------------------------------------------------------------------
    // Section 5: callback stubs (JVM implementation)
    // -------------------------------------------------------------------------

    "transient callback → per-call Arena.ofConfined closed in finally" in {
        val spec = mkTrait(
            "Sort",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
                    "qsort",
                    List(
                        ParamSpec("base", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("count", TypeRef.IntT),
                        ParamSpec("elemSize", TypeRef.IntT),
                        ParamSpec("cmp", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))
                    ),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        // Per-call Arena allocation.
        assert(src.contains("val cbArena = Arena.ofConfined().nn"))
        // II_I shape (the qsort comparator) is in the JVM-safe catalog so the emitter routes
        // it to the specialised bridge that skips the generic `MethodHandle.asType` boxing adapter.
        assert(src.contains("UpcallBridge.stubShape_II_I(cmp,"))
        assert(src.contains("cbQsortCmpDesc"))
        // cbArena.close() in finally after scratch reset.
        assert(src.contains("cbArena.close()"))
        assert(src.contains("__kyoScratch$.reset(__kyoMark$)"))
        assert(src.contains("qsortMH.invokeExact(errnoSeg, baseSeg, count, elemSize, cmpStub)"))
        // No TransientStubCache references.
        assert(!src.contains("TransientStubCache"))
        assert(!src.contains("__cbSlot_"))
    }

    "retained callback → cbArena derived from JvmGuard.unsafeArena; finally keeps single-line reset" in {
        val spec = mkTrait(
            "Epoll",
            "kyo_epoll",
            List(
                mkMethod(
                    "epollAdd",
                    "epoll_add",
                    List(
                        ParamSpec("guard", TypeRef.GuardT),
                        ParamSpec("epfd", TypeRef.IntT),
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("onEvent", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    kind = CallbackKind.Retained
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("val cbArena = guard.asInstanceOf[kyo.ffi.internal.JvmGuard].unsafeArena"))
        // I_U shape → specialised bridge, no generic `asType` boxing chain.
        assert(src.contains("UpcallBridge.stubShape_I_U(onEvent,"))
        assert(src.contains("cbEpollAddOnEventDesc"))
        // The guard does NOT appear in the invokeExact args, only in the arena lookup.
        assert(src.contains("epollAddMH.invokeExact(errnoSeg, epfd, fd, onEventStub)"))
        // No Arena.ofConfined for retained methods; the guard owns the arena.
        assert(!src.contains("Arena.ofConfined"))
        // Finally remains the single-line form (no cbArena.close(), the guard owns lifetime).
        assert(src.contains("finally __kyoScratch$.reset(__kyoMark$)"))
    }

    "transient callback companion emits MethodHandle with ADDRESS for the function-pointer param" in {
        val spec = mkTrait(
            "Sort",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
                    "qsort",
                    List(
                        ParamSpec("base", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("count", TypeRef.IntT),
                        ParamSpec("elemSize", TypeRef.IntT),
                        ParamSpec("cmp", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))
                    ),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("private val qsortMH: MethodHandle = linker.downcallHandle("))
        // The C-level descriptor is (ptr, int, int, fn*)->void, the callback slot is an ADDRESS.
        assert(src.contains("FunctionDescriptor.ofVoid(ADDRESS, JAVA_INT, JAVA_INT, ADDRESS)"))
    }

    "transient callback companion emits FunctionDescriptor val for each callback param" in {
        val spec = mkTrait(
            "Sort",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
