    "JVM-safe catalog shapes dispatch to specialised UpcallBridge.stubShape_<SHAPE>" in {
        // Each of the 5 primitive-only JVM-safe shapes (V_U, I_U, I_I, II_I, JJ_I) maps to the matching
        // specialised bridge. A single binding with 5 methods lets one spec cover the full catalog.
        val spec = mkTrait(
            "Shapes",
            "kyo_shapes",
            List(
                mkMethod(
                    "callV",
                    "call_v",
                    List(ParamSpec("cb", TypeRef.FnPtrT(Nil, TypeRef.UnitT))),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                ),
                mkMethod(
                    "callIU",
                    "call_iu",
                    List(ParamSpec("cb", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                ),
                mkMethod(
                    "callII",
                    "call_ii",
                    List(ParamSpec("cb", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.IntT))),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                ),
                mkMethod(
                    "callIII",
                    "call_iii",
                    List(ParamSpec("cb", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                ),
                mkMethod(
                    "callJJI",
                    "call_jji",
                    List(ParamSpec("cb", TypeRef.FnPtrT(List(TypeRef.LongT, TypeRef.LongT), TypeRef.IntT))),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        assert(src.contains("UpcallBridge.stubShape_V_U(cb,"))
        assert(src.contains("UpcallBridge.stubShape_I_U(cb,"))
        assert(src.contains("UpcallBridge.stubShape_I_I(cb,"))
        assert(src.contains("UpcallBridge.stubShape_II_I(cb,"))
        assert(src.contains("UpcallBridge.stubShape_JJ_I(cb,"))
        // Generic stub path must NOT be emitted for these catalog shapes.
        assert(!src.contains("UpcallBridge.stub0(cb,"))
        assert(!src.contains("UpcallBridge.stub1(cb,"))
        assert(!src.contains("UpcallBridge.stub2(cb,"))
    }

    "non-catalog callback shape falls back to the generic UpcallBridge.stubN path" in {
