    "TcpBindings fixture emits all four methods with expected shapes" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(
                mkMethod(
                    "tcpConnect",
                    "tcp_connect",
                    List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                    ReturnShape.MultiValue(cr),
                    blocking = true
                ),
                mkMethod(
                    "tcpClose",
                    "tcp_close",
                    List(ParamSpec("fd", TypeRef.IntT)),
                    ReturnShape.Void
                ),
                mkMethod(
                    "tcpRead",
                    "tcp_read",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("maxLen", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                ),
                mkMethod(
                    "tcpWrite",
                    "tcp_write",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("len", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                )
            ),
            structs = List(cr)
        )

        val src = JvmEmitter.emit(spec)

        // Impl class skeleton.
        assert(src.contains("final class TcpBindingsImpl extends TcpBindings:"))
        assert(src.contains("    import TcpBindingsImpl.*"))
        assert(src.contains("end TcpBindingsImpl"))

        // Each method appears in the impl. Every binding method takes a trailing `(using kyo.AllowUnsafe)`; the three
        // @Ffi.blocking methods return `kyo.Fiber.Unsafe[…, Any]`; tcpClose is non-blocking and returns a plain value.
        assert(src.contains(
            "def tcpConnect(host: String, port: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[kyo.example.ConnectResult, Any] ="
        ))
        assert(src.contains("def tcpClose(fd: Int)(using kyo.AllowUnsafe): Unit ="))
        assert(src.contains("def tcpRead(fd: Int, buf: Buffer[Byte], maxLen: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[Int, Any] ="))
        assert(src.contains("def tcpWrite(fd: Int, buf: Buffer[Byte], len: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[Int, Any] ="))

        // Companion with MH bindings.
        assert(src.contains("private val tcpConnectMH: MethodHandle = linker.downcallHandle("))
        assert(src.contains("private val tcpCloseMH: MethodHandle = linker.downcallHandle("))
        assert(src.contains("private val tcpReadMH: MethodHandle = linker.downcallHandle("))
        assert(src.contains("private val tcpWriteMH: MethodHandle = linker.downcallHandle("))

        // tcpClose: not @Ffi.blocking, no Array → capture only (critOff dropped for JDK 21 compat).
        val closeMhBlock = extractMhBlock(src, "tcpClose")
        assert(closeMhBlock.contains("FunctionDescriptor.ofVoid(JAVA_INT)"))
        assert(closeMhBlock.contains("capture"))
        assert(!closeMhBlock.contains("critOff"))

        // tcpConnect: @Ffi.blocking, multi-value → capture only
        val connectBlock = extractMhBlock(src, "tcpConnect")
        assert(connectBlock.contains("capture"))
        assert(!connectBlock.contains("critOn"))
        assert(!connectBlock.contains("critOff"))
    }

