    "non-blocking + Array companion emits a runtime hasCriticalApi reflective gate" in {
        val spec = mkTrait(
            "Hash",
            "kyo_hash",
            List(
                mkMethod(
                    "digest",
                    "digest",
                    List(ParamSpec("data", TypeRef.ArrayT(TypeRef.ByteT)), ParamSpec("len", TypeRef.IntT)),
                    ReturnShape.Primitive(TypeRef.IntT)
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        // Reflective probe of the JDK 22+ method must be present.
        assert(src.contains("private val hasCriticalApi: Boolean"))
        assert(src.contains("classOf[Linker.Option].getMethod(\"critical\", classOf[Boolean])"))
        assert(src.contains("catch case _: Throwable => false"))
        // critOn becomes Linker.Option | Null and is conditionally initialized.
        assert(src.contains("private val critOn: Linker.Option | Null"))
        assert(src.contains("if hasCriticalApi then Linker.Option.critical(true) else null"))
        // mkOpts helper filters nullable options before passing to downcallHandle.
        assert(src.contains("private def mkOpts(opts: Linker.Option | Null*): Array[Linker.Option]"))
        // The downcall handle for the array-bearing method splats the filtered options.
        val mh = extractMhBlock(src, "digest")
        assert(mh.contains("mkOpts(capture, critOn)*"))
    }

