                    hasVarargs = true
                )
            )
        )
        val src = JvmEmitter.emit(spec)
        // Generated method signature accepts args: Any* and the binding tier's trailing `(using kyo.AllowUnsafe)`.
        assert(src.contains("def vsum(count: Int, args: Any*)(using kyo.AllowUnsafe): Int"))
        // Panama requires `Linker.Option.firstVariadicArg(n)` to mark the fixed-arity boundary.
        assert(src.contains("Linker.Option.firstVariadicArg(1)"))
        // Dispatch helper routes Any values to the appropriate Panama ValueLayout at runtime.
        assert(src.contains("VariadicMarshaller"))
        // The emitted source must parse.
        val (ok, errs) = ScalaParseProbe.parses(src)
        assert(ok == true, s"emitted source did not parse:\n$src\n\nerrors:\n$errs\n")
    }

    // -------------------------------------------------------------------------
