    /** Extract the full MH declaration block (up to and including the closing paren at indent 4) for a method. */
    private def extractMhBlock(src: String, scalaName: String)(using kyo.test.AssertScope): String =
        val mhDecl = s"private val ${scalaName}MH: MethodHandle = linker.downcallHandle("
        val start  = src.indexOf(mhDecl)
        if start < 0 then fail(s"MH declaration for $scalaName not found in emitted source")
        // The block ends at the first line containing just "    )" after start.
        val terminator = "\n    )"
        val endIdx     = src.indexOf(terminator, start)
        if endIdx < 0 then fail(s"MH block for $scalaName not closed in emitted source")
        src.substring(start, endIdx + terminator.length)
    end extractMhBlock

